	private void analyze(QueryModelNode node, Set<String> guaranteedBindings, boolean guaranteedBindingsTainted) {
		if (node == null) {
			return;
		}

		NodeInfo info = inspect(node);
		boolean selfTainted = guaranteedBindingsTainted || !info.supportedSelf;

		if (isExact(node, Join.class)) {
			analyzeJoin((Join) node, guaranteedBindings, guaranteedBindingsTainted);
			return;
		}
		if (isExact(node, LeftJoin.class)) {
			analyzeLeftJoin((LeftJoin) node, guaranteedBindings, guaranteedBindingsTainted);
			return;
		}
		if (isClass(node, NJOIN_CLASS)) {
			analyzeNJoin(node, guaranteedBindings, guaranteedBindingsTainted);
			return;
		}
		if (isExact(node, Filter.class)) {
			analyzeFilter((Filter) node, guaranteedBindings, guaranteedBindingsTainted, info.supportedSelf);
			return;
		}
		if (isExact(node, Projection.class)) {
			analyzeProjection((Projection) node, guaranteedBindings, guaranteedBindingsTainted, info.supportedSelf);
			return;
		}
		if (isExact(node, Extension.class)) {
			analyzeExtension((Extension) node, guaranteedBindings, guaranteedBindingsTainted, info.supportedSelf);
			return;
		}
		if (isExact(node, Group.class)) {
			analyzeGroup((Group) node, guaranteedBindings, guaranteedBindingsTainted, info.supportedSelf);
			return;
		}
		if (isExact(node, Order.class)) {
			analyzeOrder((Order) node, guaranteedBindings, guaranteedBindingsTainted, info.supportedSelf);
			return;
		}
		if (isExact(node, MultiProjection.class)) {
			analyzeMultiProjection((MultiProjection) node, guaranteedBindings, guaranteedBindingsTainted,
					info.supportedSelf);
			return;
		}
		if (isResetTupleNode(node)) {
			for (QueryModelNode child : directChildren(node)) {
				analyze(child, externalBindings, false);
			}
			return;
		}
		if (isExact(node, Service.class)) {
			Service service = (Service) node;
			analyze(service.getServiceRef(), guaranteedBindings, selfTainted);
			analyze(service.getArg(), externalBindings, false);
			return;
		}
		if (isClass(node, FEDX_SERVICE_CLASS)) {
			Object service = invoke(node, "getService");
			if (service instanceof QueryModelNode) {
				analyze((QueryModelNode) service, externalBindings, false);
			}
			return;
		}
		if (isExact(node, Union.class) || isExact(node, Difference.class) || isExact(node, Intersection.class)
				|| isClass(node, NUNION_CLASS)) {
			for (QueryModelNode child : directChildren(node)) {
				analyze(child, guaranteedBindings, selfTainted);
			}
			return;
		}

		for (QueryModelNode child : directChildren(node)) {
			analyze(child, guaranteedBindings, selfTainted);
		}
	}

	private void analyzeJoin(Join join, Set<String> guaranteedBindings, boolean guaranteedBindingsTainted) {
		TupleExpr left = join.getLeftArg();
		TupleExpr right = join.getRightArg();
		NodeInfo leftInfo = inspect(left);
		NodeInfo rightInfo = inspect(right);

		if (globallySupported && !guaranteedBindingsTainted && leftInfo.supportedSubtree && rightInfo.supportedSubtree
				&& isCorrelationEmpty(leftInfo.bindingNames, leftInfo.use, rightInfo.bindingNames, rightInfo.use,
						guaranteedBindings)
				&& !regionConnects(join, List.of(left), List.of(right), guaranteedBindings)) {
			joinTypeByNode.put(join, "cartesian join");
		}

		analyze(left, guaranteedBindings, guaranteedBindingsTainted);
		analyze(right, union(guaranteedBindings, leftInfo.assuredBindingNames),
				guaranteedBindingsTainted || !leftInfo.supportedSubtree);
	}

	private void analyzeLeftJoin(LeftJoin leftJoin, Set<String> guaranteedBindings, boolean guaranteedBindingsTainted) {
		TupleExpr left = leftJoin.getLeftArg();
		TupleExpr right = leftJoin.getRightArg();
		NodeInfo leftInfo = inspect(left);
		NodeInfo rightInfo = inspect(right);

		analyze(left, guaranteedBindings, guaranteedBindingsTainted);
		analyze(right, union(guaranteedBindings, leftInfo.assuredBindingNames),
				guaranteedBindingsTainted || !leftInfo.supportedSubtree);
		if (leftJoin.getCondition() != null) {
			analyze(leftJoin.getCondition(), union(guaranteedBindings, leftInfo.bindingNames, rightInfo.bindingNames),
					guaranteedBindingsTainted || !leftInfo.supportedSubtree || !rightInfo.supportedSubtree);
		}
	}

	private void analyzeNJoin(QueryModelNode nJoin, Set<String> guaranteedBindings, boolean guaranteedBindingsTainted) {
		List<TupleExpr> args = invokeList(nJoin, "getArgs", TupleExpr.class);
		if (args.isEmpty()) {
			return;
		}

		TupleExpr first = args.get(0);
		NodeInfo prefixInfo = inspect(first);
		Set<String> prefixBindingNames = new LinkedHashSet<>(prefixInfo.bindingNames);
		Set<String> prefixUse = new LinkedHashSet<>(prefixInfo.use);
		Set<String> prefixAssuredBindingNames = new LinkedHashSet<>(prefixInfo.assuredBindingNames);
		boolean prefixSupported = prefixInfo.supportedSubtree;
		List<String> boundaries = new ArrayList<>();

		analyze(first, guaranteedBindings, guaranteedBindingsTainted);

		for (int index = 1; index < args.size(); index++) {
			TupleExpr arg = args.get(index);
			NodeInfo argInfo = inspect(arg);

			if (globallySupported && !guaranteedBindingsTainted && prefixSupported && argInfo.supportedSubtree
					&& isCorrelationEmpty(prefixBindingNames, prefixUse, argInfo.bindingNames, argInfo.use,
							guaranteedBindings)
					&& !regionConnects(nJoin, args.subList(0, index), List.of(arg), guaranteedBindings)) {
				boundaries.add(formatBoundary(index + 1));
			}

			analyze(arg, union(guaranteedBindings, prefixAssuredBindingNames),
					guaranteedBindingsTainted || !prefixSupported);
			prefixBindingNames.addAll(argInfo.bindingNames);
			prefixUse.addAll(argInfo.use);
			prefixAssuredBindingNames.addAll(argInfo.assuredBindingNames);
			prefixSupported &= argInfo.supportedSubtree;
		}

		if (!boundaries.isEmpty()) {
			joinTypeByNode.put(nJoin, "cartesian join boundaries: " + String.join(", ", boundaries));
		}
	}

	private void analyzeFilter(Filter filter, Set<String> guaranteedBindings, boolean guaranteedBindingsTainted,
			boolean supportedSelf) {
		NodeInfo argInfo = inspect(filter.getArg());
		analyze(filter.getArg(), guaranteedBindings, guaranteedBindingsTainted || !supportedSelf);
		analyze(filter.getCondition(), union(guaranteedBindings, argInfo.bindingNames),
				guaranteedBindingsTainted || !supportedSelf || !argInfo.supportedSubtree);
	}

	private void analyzeProjection(Projection projection, Set<String> guaranteedBindings,
			boolean guaranteedBindingsTainted,
			boolean supportedSelf) {
		NodeInfo argInfo = inspect(projection.getArg());
		analyze(projection.getProjectionElemList(), union(guaranteedBindings, argInfo.bindingNames),
				guaranteedBindingsTainted || !supportedSelf || !argInfo.supportedSubtree);
		if (projection.getProjectionContext() != null) {
			analyze(projection.getProjectionContext(), guaranteedBindings, guaranteedBindingsTainted || !supportedSelf);
		}
		if (projection.isSubquery()) {
			analyze(projection.getArg(), externalBindings, false);
		} else {
			analyze(projection.getArg(), guaranteedBindings, guaranteedBindingsTainted || !supportedSelf);
		}
	}

	private void analyzeExtension(Extension extension, Set<String> guaranteedBindings,
			boolean guaranteedBindingsTainted,
			boolean supportedSelf) {
		NodeInfo argInfo = inspect(extension.getArg());
		analyze(extension.getArg(), guaranteedBindings, guaranteedBindingsTainted || !supportedSelf);

		Set<String> visibleBindings = union(guaranteedBindings, argInfo.bindingNames);
		boolean visibleBindingsTainted = guaranteedBindingsTainted || !supportedSelf || !argInfo.supportedSubtree;
		for (ExtensionElem element : extension.getElements()) {
			analyze(element, visibleBindings, visibleBindingsTainted);
			visibleBindings = union(visibleBindings, Set.of(element.getName()));
			visibleBindingsTainted |= !inspect(element).supportedSubtree;
		}
	}

	private void analyzeGroup(Group group, Set<String> guaranteedBindings, boolean guaranteedBindingsTainted,
			boolean supportedSelf) {
		NodeInfo argInfo = inspect(group.getArg());
		analyze(group.getArg(), guaranteedBindings, guaranteedBindingsTainted || !supportedSelf);
		Set<String> visibleBindings = union(guaranteedBindings, argInfo.bindingNames, group.getGroupBindingNames());
		boolean visibleBindingsTainted = guaranteedBindingsTainted || !supportedSelf || !argInfo.supportedSubtree;
		for (GroupElem groupElem : group.getGroupElements()) {
			analyze(groupElem, visibleBindings, visibleBindingsTainted);
		}
	}

